import{b as a,I as s,g as t,j as n}from"./chunks/framework.DUo3J_Qe.js";const h=JSON.parse(`{"title":"Détection d'arbres","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/models/tree-detection.md","filePath":"fr/guide/models/tree-detection.md"}`),r={name:"fr/guide/models/tree-detection.md"};function i(o,e,l,p,d,u){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="detection-d-arbres" tabindex="-1">Détection d&#39;arbres <a class="header-anchor" href="#detection-d-arbres" aria-label="Permalink to &quot;Détection d&#39;arbres&quot;">​</a></h1><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Le modèle de détection d&#39;arbres prend en entrée une <strong>orthophoto RGB</strong> (tuile IGN 20 cm/px) et produit un <strong>masque de segmentation</strong> pixel à pixel. Ce masque est ensuite converti en polygones GeoJSON affichés sur la carte.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tuile IGN (RGB)  →  U-Net  →  Masque binaire  →  Polygones GeoJSON</span></span></code></pre></div><h2 id="pipeline-en-trois-etapes" tabindex="-1">Pipeline en trois étapes <a class="header-anchor" href="#pipeline-en-trois-etapes" aria-label="Permalink to &quot;Pipeline en trois étapes&quot;">​</a></h2><h3 id="_1-exploration-du-dataset-explore-dataset-py" tabindex="-1">1. Exploration du dataset (<code>explore_dataset.py</code>) <a class="header-anchor" href="#_1-exploration-du-dataset-explore-dataset-py" aria-label="Permalink to &quot;1. Exploration du dataset (\`explore_dataset.py\`)&quot;">​</a></h3><p>Avant d&#39;entraîner quoi que ce soit, on visualise les données brutes pour comprendre ce que le modèle va recevoir en entrée et ce qu&#39;il devra apprendre à produire.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">conda</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> activate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> geoml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model/src/explore_dataset.py</span></span></code></pre></div><p>Le script télécharge une mosaïque 3×3 de tuiles IGN sur la <strong>Forêt de Fontainebleau</strong> (zone riche en feuillage, idéale pour tester) et affiche trois panneaux :</p><p><strong>Panneau 1 — Orthophoto RGB</strong> L&#39;image brute IGN. C&#39;est l&#39;entrée exacte que recevra U-Net. Chaque pixel a trois valeurs : Rouge, Vert, Bleu (0–255).</p><p><strong>Panneau 2 — Heatmap EGI</strong> L&#39;Excess Green Index : <code>EGI = 2×Vert - Rouge - Bleu</code>. La végétation reflète beaucoup de vert → valeur EGI élevée → pixel jaune/vif sur la heatmap. Le béton, l&#39;asphalte et les toits ont une valeur EGI faible → pixel sombre.</p><p><strong>Panneau 3 — Masque binaire</strong> On applique un seuil automatique (méthode Otsu) sur la heatmap EGI : pixels au-dessus du seuil = arbre (<code>1</code>), en dessous = fond (<code>0</code>). Ce masque est la <strong>vérité terrain approximative</strong> utilisée pour entraîner U-Net.</p><div class="info custom-block"><p class="custom-block-title">Pourquoi &quot;approximative&quot; ?</p><p>L&#39;EGI confond parfois gazon et arbre, rate les arbres en zone ombragée. C&#39;est un <strong>label faible</strong> — suffisant pour démarrer l&#39;entraînement, mais à améliorer ensuite avec des annotations manuelles ou un dataset externe.</p></div><h3 id="_2-preparation-des-patches" tabindex="-1">2. Préparation des patches <a class="header-anchor" href="#_2-preparation-des-patches" aria-label="Permalink to &quot;2. Préparation des patches&quot;">​</a></h3><p>U-Net travaille sur des <strong>patches carrés de 256×256 px</strong>. L&#39;orthophoto complète est découpée en grille de patches avec chevauchement pour éviter les effets de bord.</p><p>Chaque patch donne une paire :</p><ul><li><code>image.npy</code> — tableau 256×256×3 (RGB normalisé 0–1)</li><li><code>mask.npy</code> — tableau 256×256×1 (binaire 0/1)</li></ul><h3 id="_3-entrainement-u-net" tabindex="-1">3. Entraînement U-Net <a class="header-anchor" href="#_3-entrainement-u-net" aria-label="Permalink to &quot;3. Entraînement U-Net&quot;">​</a></h3><p>Le modèle apprend à reproduire le masque à partir de l&#39;image RGB. Après entraînement, il généralise : il reconnaît les couronnes d&#39;arbres par leur <strong>texture et leur forme</strong>, pas seulement par leur couleur verte.</p><h2 id="structure-des-fichiers" tabindex="-1">Structure des fichiers <a class="header-anchor" href="#structure-des-fichiers" aria-label="Permalink to &quot;Structure des fichiers&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>model/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── explore_dataset.py   # Étape 1 — visualiser données brutes</span></span>
<span class="line"><span>│   ├── dataset.py           # Étape 2 — Dataset PyTorch (patches)</span></span>
<span class="line"><span>│   ├── model.py             # Définition U-Net</span></span>
<span class="line"><span>│   └── train.py             # Boucle d&#39;entraînement</span></span>
<span class="line"><span>├── data/</span></span>
<span class="line"><span>│   └── ign-sample/          # Tuiles IGN téléchargées + preview</span></span>
<span class="line"><span>├── weights/                 # Poids entraînés (.pth) — ignoré par git</span></span>
<span class="line"><span>└── environment.yml          # Dépendances conda</span></span></code></pre></div><h2 id="lien-avec-la-methode-classique-egi" tabindex="-1">Lien avec la méthode classique (EGI) <a class="header-anchor" href="#lien-avec-la-methode-classique-egi" aria-label="Permalink to &quot;Lien avec la méthode classique (EGI)&quot;">​</a></h2><p>L&#39;application utilise déjà une détection par EGI (<code>tree-detection/backend/detection/detect.py</code>). Le U-Net ne remplace pas cet algorithme immédiatement — il apprend d&#39;abord <em>à partir</em> de ses résultats (les masques EGI servent de labels d&#39;entraînement).</p><p>Une fois le modèle entraîné et validé, il prendra la relève : même entrée (tuile RGB), même sortie (masque/polygones), mais une précision bien supérieure sur les cas difficiles.</p>`,24)])])}const m=a(r,[["render",i]]);export{h as __pageData,m as default};
